Bash(.venv/bin/python3 - << 'EOF'
import json
import math

def dist\(a, b\):
    return math.sqrt\(\(a[0]-b[0]\)**2 + \(a[1]-b[1]\)**2\)

with open\('yolo_cache_v7.json'\) as f:
    cache = json.load\(f\)

with open\('ball_labels.json'\) as f:
    labels = json.load\(f\)

# Get GT positions
gt = {}
for item in labels:
    if 'frame' in item and 'x' in item:
        gt[item['frame']] = \(item['x'], item['y']\)

# Find all HC detections \(conf >= 0.55\) and check accuracy vs GT
print\("=== HC detections \(conf >= 0.55\) analysis ==="\)
for frame_key, data in sorted\(cache.items\(\), key=lambda x: int\(x[0]\)\):
    fi = int\(frame_key\)
    balls = data.get\('balls', []\)
    hc_balls = [b for b in balls if b[2] >= 0.55]
    if hc_balls and fi in gt:
        for b in hc_balls:
            err = dist\(\(b[0], b[1]\), gt[fi]\)
            flag = " <-- HC FP!" if err > 100 else ""
            print\(f"  f{fi:4d}: det=\({b[0]:.0f},{b[1]:.0f}\) c={b[2]:.2f}  gt={gt[fi]}  err={err:.0f}px{flag}"\)
EOF)
